// ═══════════════════════════════════════════════════════════════
// TEMPLATE SANITIZADO — db_confirmar_reserva v1
// ═══════════════════════════════════════════════════════════════
// Este JSON es un template genérico para importar en n8n.
// No contiene credenciales, IDs de Sheet ni IDs de workflow reales.
//
// Antes de importar, reemplazar:
//   __SHEETS_ID__                              → ID del Google Sheet del entorno
//   __CREDENTIAL_ID__                          → ID de la credencial OAuth en n8n
//   __CREDENTIAL_NAME__                        → Nombre de la credencial OAuth en n8n
//   __RECALCULAR_DISPONIBILIDAD_WORKFLOW_ID__  → ID de db_recalcular_disponibilidad
//   __RECALCULAR_DISPONIBILIDAD_WORKFLOW_NAME__ → Nombre de db_recalcular_disponibilidad
//
// El mismo template sirve para DEV, TEST y PROD.
// Solo cambia __SHEETS_ID__ y las credenciales.
// ═══════════════════════════════════════════════════════════════

// ═══════════════════════════════════════════════════════════════
// NODO 1 — Resolver Input
// ═══════════════════════════════════════════════════════════════
// ALCANCE v1:
// ✅ Confirma reserva a partir de PRE_RESERVA en pago_en_revision
//    y PAGO en en_revision.
// ✅ Crea RESERVA con estado = confirmada.
// ✅ Actualiza PRE_RESERVAS.estado → convertida.
// ✅ Actualiza PAGOS.estado → confirmado, llena id_reserva,
//    validado_por, validado_en.
// ✅ Detecta conflicto contra RESERVAS existentes confirmadas/activas.
// ✅ Escribe LOG_CAMBIOS.
// ✅ Recalcula DISPONIBILIDAD_CACHE al final.
//
// ❌ FUERA DE ALCANCE en v1:
//    - MercadoPago automático
//    - WhatsApp / notificaciones
//    - IA
//    - Creación o modificación de HUÉSPEDES
//    - Motor de precios / id_tarifa_aplicada
//    - encargado_semana automático (calendario de turnos)
//    - CONSULTAS: no se toca
//
// ⚠️  SHEETS_ID — __ENTORNO__
// Valor actual: __SHEETS_ID__
//
// ⚠️  WORKFLOW ID — db_recalcular_disponibilidad
// __RECALCULAR_DISPONIBILIDAD_WORKFLOW_NAME__ → ID: __RECALCULAR_DISPONIBILIDAD_WORKFLOW_ID__
//
// ⚠️  id_reserva usa max + 1. Race condition posible en alta
// concurrencia. Para producción, migrar a UUID.
//
// ⚠️  encargado_semana es input opcional en v1.
// En producción debería resolverse automáticamente según calendario
// de turnos o asignación operativa (Franco / Rodrigo).
// ═══════════════════════════════════════════════════════════════

const SHEETS_ID = '__SHEETS_ID__'; // __ENTORNO__

// ── MANUAL_INPUT ──────────────────────────────────────────────
// Editar estos valores para pruebas manuales del entorno correspondiente.
// Se usan SOLO si el Manual Trigger viene vacío.
const MANUAL_INPUT = {
  id_prereserva:    1,
  id_pago:          1,        // opcional pero recomendado
  validado_por:     'Franco',
  encargado_semana: '',       // opcional — vacío si no se asigna
  notas:            'Pago verificado manualmente',
  source_event:     'manual'   // editar según entorno
};
// ─────────────────────────────────────────────────────────────

const raw              = $input.first()?.json ?? {};
const usandoManualInput = !raw.id_prereserva;
const input            = usandoManualInput ? MANUAL_INPUT : raw;

const id_prereserva    = parseInt(String(input.id_prereserva ?? ''), 10);
const id_pago          = input.id_pago ? parseInt(String(input.id_pago), 10) : null;
const validado_por     = String(input.validado_por     ?? '').trim();
const encargado_semana = String(input.encargado_semana ?? '').trim();
const notas            = String(input.notas            ?? '').trim();
const source_event     = String(input.source_event     ?? 'manual').trim();

// ── Validaciones ─────────────────────────────────────────────
const errores = [];
if (isNaN(id_prereserva) || id_prereserva <= 0)
  errores.push('id_prereserva es obligatorio y debe ser entero positivo');
if (!validado_por)
  errores.push('validado_por es obligatorio en v1');
if (id_pago !== null && (isNaN(id_pago) || id_pago <= 0))
  errores.push('id_pago debe ser entero positivo si se proporciona');

if (errores.length > 0)
  return [{ json: { ok: false, error: 'input_invalido', detalle: errores, _validado: false } }];

return [{ json: {
  SHEETS_ID,
  id_prereserva,
  id_pago,
  validado_por,
  encargado_semana,
  notas,
  source_event,
  ts_inicio: new Date().toISOString(),
  _validado: true,
  _usando_manual_input: usandoManualInput
}}];

// ═══════════════════════════════════════════════════════════════
// NODO 2 — Verificar datos
// ═══════════════════════════════════════════════════════════════
// Validaciones en orden:
//   1. PRE_RESERVA existe y tiene estado = pago_en_revision
//   2. PAGO existe, tiene estado = en_revision y corresponde
//      a la PRE_RESERVA
//   3. No hay conflicto con RESERVAS confirmadas/activas en
//      las mismas fechas/cabaña
//   4. Calcula id_reserva, monto_saldo, precio_pendiente
// ═══════════════════════════════════════════════════════════════

const inputData = $('Resolver Input').first().json;
const ahora     = new Date();

function parseFechaMs(val) {
  if (!val && val !== 0) return null;
  if (typeof val === 'number') {
    const d = new Date(Date.UTC(1899, 11, 30) + val * 86400000);
    return isNaN(d.getTime()) ? null : d.getTime();
  }
  const s = String(val).trim().split('T')[0];
  if (!/^\d{4}-\d{2}-\d{2}$/.test(s)) return null;
  const [y, m, d] = s.split('-').map(Number);
  return Date.UTC(y, m - 1, d, 12, 0, 0);
}

function normRows(agg) {
  return (agg?.data ?? []).filter(r => r && Object.keys(r).some(k => String(r[k]).trim() !== ''));
}

const prereservas = normRows($('Agg PRE_RESERVAS').first()?.json);
const pagos       = normRows($('Agg PAGOS').first()?.json);
const reservas    = normRows($('Agg RESERVAS').first()?.json);

// ── 1. Verificar PRE_RESERVA ──────────────────────────────────
const prereserva = prereservas.find(
  p => parseInt(String(p.id_prereserva), 10) === inputData.id_prereserva
);

if (!prereserva)
  return [{ json: {
    ok: false, error: 'prereserva_no_encontrada',
    detalle: [`id_prereserva ${inputData.id_prereserva} no existe en PRE_RESERVAS`],
    _verificacion_ok: false
  }}];

const estadoPR = String(prereserva.estado ?? '').trim();
if (estadoPR !== 'pago_en_revision')
  return [{ json: {
    ok: false, error: 'prereserva_estado_invalido',
    detalle: [`PRE_RESERVA ${inputData.id_prereserva} tiene estado '${estadoPR}'. Se requiere 'pago_en_revision'.`],
    estado_actual: estadoPR,
    _verificacion_ok: false
  }}];

// ── 2. Verificar PAGO ─────────────────────────────────────────
let pago = null;

if (inputData.id_pago) {
  // Buscar por id_pago explícito
  pago = pagos.find(p => parseInt(String(p.id_pago), 10) === inputData.id_pago);
  if (!pago)
    return [{ json: {
      ok: false, error: 'pago_no_encontrado',
      detalle: [`id_pago ${inputData.id_pago} no existe en PAGOS`],
      _verificacion_ok: false
    }}];
} else {
  // Buscar por id_prereserva + estado = en_revision
  const pagosEnRevision = pagos.filter(
    p => parseInt(String(p.id_prereserva), 10) === inputData.id_prereserva &&
         String(p.estado ?? '').trim() === 'en_revision'
  );
  if (pagosEnRevision.length === 0)
    return [{ json: {
      ok: false, error: 'pago_no_encontrado',
      detalle: [`No hay pagos en estado en_revision para id_prereserva ${inputData.id_prereserva}`],
      _verificacion_ok: false
    }}];
  if (pagosEnRevision.length > 1)
    return [{ json: {
      ok: false, error: 'pago_duplicado_ambiguo',
      detalle: [`Hay ${pagosEnRevision.length} pagos en_revision para id_prereserva ${inputData.id_prereserva}. Especificar id_pago en el input.`],
      pagos_en_revision: pagosEnRevision.map(p => ({ id_pago: p.id_pago, created_at: p.created_at })),
      _verificacion_ok: false
    }}];
  pago = pagosEnRevision[0];
}

// Verificar estado del pago
const estadoPago = String(pago.estado ?? '').trim();
if (estadoPago !== 'en_revision')
  return [{ json: {
    ok: false, error: 'pago_estado_invalido',
    detalle: [`PAGO ${pago.id_pago} tiene estado '${estadoPago}'. Se requiere 'en_revision'.`],
    estado_actual: estadoPago,
    _verificacion_ok: false
  }}];

// Verificar que el pago corresponde a la PRE_RESERVA
const pagoIdPrereserva = parseInt(String(pago.id_prereserva ?? ''), 10);
if (pagoIdPrereserva !== inputData.id_prereserva)
  return [{ json: {
    ok: false, error: 'pago_no_corresponde',
    detalle: [`PAGO ${pago.id_pago} corresponde a id_prereserva ${pagoIdPrereserva}, no a ${inputData.id_prereserva}.`],
    _verificacion_ok: false
  }}];

// ── 3. Verificar conflicto con RESERVAS existentes ────────────
const id_cabana  = parseInt(String(prereserva.id_cabana), 10);
const msIn       = parseFechaMs(prereserva.fecha_in);
const msOut      = parseFechaMs(prereserva.fecha_out);

if (msIn === null || msOut === null)
  return [{ json: {
    ok: false, error: 'input_invalido',
    detalle: ['PRE_RESERVA tiene fechas inválidas o vacías. No se puede confirmar.'],
    _verificacion_ok: false
  }}];

const conflicto = reservas.find(r => {
  if (parseInt(String(r.id_cabana), 10) !== id_cabana) return false;
  if (!['confirmada', 'activa'].includes(String(r.estado ?? '').trim())) return false;
  const rIn  = parseFechaMs(r.fecha_checkin);
  const rOut = parseFechaMs(r.fecha_checkout);
  if (rIn === null || rOut === null) return false;
  return rIn < msOut && rOut > msIn;
});

if (conflicto)
  return [{ json: {
    ok: false, error: 'conflicto_reserva_existente',
    detalle: [`Ya existe una RESERVA (id=${conflicto.id_reserva}) en estado '${conflicto.estado}' que se solapa con las fechas solicitadas.`],
    reserva_conflicto: { id_reserva: conflicto.id_reserva, fecha_checkin: conflicto.fecha_checkin, fecha_checkout: conflicto.fecha_checkout, estado: conflicto.estado },
    _verificacion_ok: false
  }}];

// ── 4. Calcular id_reserva y montos ──────────────────────────
const ids_reserva = reservas
  .map(r => parseInt(String(r.id_reserva ?? ''), 10))
  .filter(n => !isNaN(n) && n > 0);
const nuevo_id_reserva = (ids_reserva.length > 0 ? Math.max(...ids_reserva) : 0) + 1;

const monto_total = parseFloat(String(prereserva.monto_total ?? '')) || null;
const monto_sena  = parseFloat(String(prereserva.monto_sena  ?? '')) || null;
const monto_saldo = (monto_total !== null && monto_sena !== null)
  ? monto_total - monto_sena : null;
const precio_pendiente = monto_total === null || monto_sena === null;

return [{ json: {
  _verificacion_ok: true,
  precio_pendiente,
  inputData,
  prereserva,
  pago,
  nuevo_id_reserva,
  monto_total,
  monto_sena,
  monto_saldo
}}];

const d = $input.first().json;
return [{ json: {
  ok:    d.ok,
  error: d.error,
  detalle: d.detalle,
  ...(d.estado_actual          ? { estado_actual: d.estado_actual }                   : {}),
  ...(d.reserva_conflicto      ? { reserva_conflicto: d.reserva_conflicto }           : {}),
  ...(d.pagos_en_revision      ? { pagos_en_revision: d.pagos_en_revision }           : {})
}}];

// ═══════════════════════════════════════════════════════════════
// NODO 3 — Preparar Fila RESERVAS
// ═══════════════════════════════════════════════════════════════
// Construye la fila completa de 24 columnas para RESERVAS.
//
// Campos copiados desde PRE_RESERVAS:
//   id_prereserva, id_cabana, id_huesped, fecha_in→fecha_checkin,
//   fecha_out→fecha_checkout, hora_checkin, hora_checkout, personas,
//   monto_total, monto_sena, canal_origen, notas
//
// Calculados:
//   id_reserva = max + 1
//   monto_saldo = monto_total - monto_sena (o vacío si faltan)
//   estado = confirmada
//
// Vacíos en v1 (diferidos):
//   id_tarifa_aplicada — motor de precios no implementado
//   mascotas, detalle_mascotas, ninos — no capturados en v1
//   encargado_semana — del input o vacío
// ═══════════════════════════════════════════════════════════════

const d     = $input.first().json;
const { inputData, prereserva, nuevo_id_reserva, monto_total, monto_sena, monto_saldo } = d;
const ahora = new Date().toISOString();

return [{ json: {
  fila_reservas: {
    id_reserva:         nuevo_id_reserva,
    id_prereserva:      prereserva.id_prereserva,
    id_cabana:          prereserva.id_cabana,
    id_huesped:         prereserva.id_huesped          ?? '',
    fecha_checkin:      prereserva.fecha_in,
    fecha_checkout:     prereserva.fecha_out,
    hora_checkin:       prereserva.hora_checkin         ?? '',
    hora_checkout:      prereserva.hora_checkout        ?? '',
    personas:           prereserva.personas,
    estado:             'confirmada',
    canal_origen:       prereserva.canal_origen         ?? '',
    id_tarifa_aplicada: '',    // diferido — motor de precios no implementado en v1
    monto_total:        monto_total                    ?? '',
    monto_sena:         monto_sena                     ?? '',
    monto_saldo:        monto_saldo                    ?? '',
    mascotas:           '',    // diferido
    detalle_mascotas:   '',    // diferido
    ninos:              '',    // diferido
    encargado_semana:   inputData.encargado_semana     ?? '',
    notas:              inputData.notas                ?? prereserva.notas ?? '',
    created_by:         inputData.validado_por,
    source_event:       inputData.source_event,
    created_at:         ahora,
    updated_at:         ahora
  },
  // Datos para actualizaciones
  update_prereserva: {
    id_prereserva: prereserva.id_prereserva,
    estado:        'convertida',
    updated_at:    ahora
  },
  update_pago: {
    id_pago:      d.pago.id_pago,
    id_reserva:   nuevo_id_reserva,
    estado:       'confirmado',
    validado_por: inputData.validado_por,
    validado_en:  ahora,
    updated_at:   ahora
  },
  // Metadata para LOG y Resumen
  nuevo_id_reserva,
  precio_pendiente: d.precio_pendiente,
  monto_total,
  monto_sena,
  monto_saldo,
  inputData
}}];

// ═══════════════════════════════════════════════════════════════
// NODO 4 — Preparar LOG_CAMBIOS
// ═══════════════════════════════════════════════════════════════
// Un único registro por ejecución exitosa.
// Si precio_pendiente = true, nivel pasa a 'warning' operativo.
// ═══════════════════════════════════════════════════════════════

const d     = $('Preparar Fila RESERVAS').first().json;
const ahora = new Date();

return [{ json: {
  id_log:           `LOG-RESERVA-${ahora.getTime()}`,
  fecha_hora:        ahora.toISOString(),
  tabla_afectada:   'RESERVAS',
  id_registro:      String(d.nuevo_id_reserva),
  campo_modificado: 'estado',
  valor_anterior:   '',
  valor_nuevo:      'confirmada',
  modificado_por:   'n8n',
  source_event:     d.inputData.source_event,
  nivel:            d.precio_pendiente ? 'warning' : 'info',
  detalle: JSON.stringify({
    id_reserva:      d.nuevo_id_reserva,
    id_prereserva:   d.inputData.id_prereserva,
    id_pago:         d.update_pago?.id_pago,
    id_cabana:       d.fila_reservas?.id_cabana,
    fecha_checkin:   d.fila_reservas?.fecha_checkin,
    fecha_checkout:  d.fila_reservas?.fecha_checkout,
    validado_por:    d.inputData.validado_por,
    precio_pendiente: d.precio_pendiente,
    monto_total:     d.monto_total,
    monto_sena:      d.monto_sena,
    monto_saldo:     d.monto_saldo
  })
}}];

// ═══════════════════════════════════════════════════════════════
// NODO FINAL — Resumen
// ═══════════════════════════════════════════════════════════════
// continueOnFail = true en Ejecutar Recalculo Final garantiza
// que este nodo siempre se ejecuta.
//
// Si el recálculo falló:
//   - La RESERVA fue creada correctamente.
//   - PRE_RESERVAS y PAGOS fueron actualizados.
//   - LOG_CAMBIOS fue escrito.
//   - Solo la cache puede estar desactualizada.
//   - Acción: ejecutar db_recalcular_disponibilidad manualmente.
// ═══════════════════════════════════════════════════════════════

const d = $('Preparar Fila RESERVAS').first().json;

const recalculoOutput = $('Ejecutar Recalculo Final').first()?.json ?? {};
const recalculo_fallo = !!recalculoOutput.error || recalculoOutput.ok === false;

return [{ json: {
  ok:                  true,
  id_reserva:          d.nuevo_id_reserva,
  id_prereserva:       d.inputData.id_prereserva,
  id_pago:             d.update_pago?.id_pago,
  estado_reserva:      'confirmada',
  estado_prereserva:   'convertida',
  estado_pago:         'confirmado',
  precio_pendiente:    d.precio_pendiente,
  monto_total:         d.monto_total    ?? null,
  monto_sena:          d.monto_sena     ?? null,
  monto_saldo:         d.monto_saldo    ?? null,
  validado_por:        d.inputData.validado_por,
  recalculo_cache:     recalculo_fallo ? 'warning' : 'ok',
  recalculo_error:     recalculo_fallo
    ? 'db_recalcular_disponibilidad falló después de confirmar la reserva. Cache puede estar desactualizada. Ejecutar recálculo manual.'
    : null,
  mensaje: 'Reserva confirmada correctamente'
}}];
